import React, { useState, useEffect } from 'react';
import { getProducibleProducts } from '../../api/productApi';

const ProductProductionList = () => {
  const [products, setProducts] = useState([]);

  useEffect(() => {
    getProducibleProducts().then(res => setProducts(res.data));
  }, []);

  return (
    <div>
      <h1>Products Possible to Produce</h1>
      <table>
        <thead>
          <tr>
            <th>Name</th><th>Price</th><th>Quantity</th><th>Materials Needed</th>
          </tr>
        </thead>
        <tbody>
          {products.map(p => (
            <tr key={p.id}>
              <td>{p.name}</td>
              <td>{p.price}</td>
              <td>{p.quantity}</td>
              <td>
                {p.materials.map(m => (
                  <div key={m.id}>
                    Material ID: {m.rawMaterialId}, Quantity: {m.quantity}
                  </div>
                ))}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default ProductProductionList;
